--
-- Table structure for table `orders`
--

CREATE TABLE `orders` (
  `id` int(11) NOT NULL,
  `payment_id` int(11) NOT NULL,
  `product_id` char(7) NOT NULL,
  `Order_id` char(16) NOT NULL,
  `Customer` varchar(50) NOT NULL,
  `Address` varchar(100) NOT NULL,
  `Total amount` int(11) NOT NULL,
  `Order-date` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

--
-- Triggers `orders`
--
DELIMITER $$
CREATE TRIGGER `set_order_number` BEFORE INSERT ON `orders` FOR EACH ROW BEGIN
    DECLARE next_id INT;

    SELECT AUTO_INCREMENT INTO next_id
    FROM information_schema.TABLES
    WHERE TABLE_SCHEMA = DATABASE()
      AND TABLE_NAME = 'orders';

    SET NEW.Order_id = CONCAT(
        NEW.product_id,
        NEW.Payment_id,
        LPAD(next_id, 8, '0')
    );
END
$$
DELIMITER ;

